#include<bits/stdc++.h>
using namespace std;
void dfs(string zhong,string hou){
    if(!(zhong.size()))return;
    char gen=hou[hou.size()-1];
    int weizhi=zhong.find(gen);
	cout<<gen;
    dfs(zhong.substr(0,weizhi),hou.substr(0,weizhi));
    dfs(zhong.substr(weizhi+1),hou.substr(weizhi,zhong.size()-weizhi-1));
}string z,h;
int main(void){
    cin>>z>>h;
    dfs(z,h);
    return false;
}
